-- Seed en/es translations for the Säljmanus items (pitches, scripts,
-- objections). Matches existing rows by their Swedish title and fills the
-- *_en / *_es columns; the UI falls back to Swedish where these are null.
UPDATE public.training_items ti
SET title_en = v.title_en,
    title_es = v.title_es,
    body_en  = v.body_en,
    body_es  = v.body_es
FROM (VALUES
  ('Säljpitch: Landningssida', 'Sales pitch: Landing page', 'Pitch de ventas: Página de aterrizaje', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Imagine every ad krona actually landing somewhere that sells. A landing page is exactly that – one razor-sharp page built for a single goal: turning visitors into customers."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "You get a lightning-fast, mobile-friendly page with a message that hits home, a form that captures every lead, and SEO baked in. From SEK 9,000 you're live – often this very week."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Most businesses lose deals by sending traffic to a cluttered site. You won't. Shall we set up your first page and start capturing leads right away?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Imagina que cada euro de publicidad aterriza en un lugar que realmente vende. Una página de aterrizaje es justo eso: una única página afilada con un solo objetivo: convertir visitantes en clientes."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Obtienes una página ultrarrápida y adaptada a móvil, con un mensaje que da en el blanco, un formulario que capta cada lead y SEO de base. Desde 9 000 SEK estás en línea, a menudo esta misma semana."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "La mayoría pierde ventas por enviar tráfico a una web desordenada. Tú no. ¿Montamos tu primera página y empezamos a captar leads ya?"}]}]}$j$::jsonb),
  ('Säljpitch: Företagshemsida', 'Sales pitch: Business website', 'Pitch de ventas: Web corporativa', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Your customers decide in three seconds. A slow or dated site sends them straight to your competitor – for good. Those are deals you never even know you lost."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Our business website gives you the opposite: a fast, sharp, sales-driven site you're proud to send people to. Up to seven pages, your own CMS so you update it yourself, responsive design, on-page SEO and Google Analytics – all for SEK 18,000."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "It's our most popular package, and that's no accident. Want me to show examples and put together a proposal for your new site?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tus clientes deciden en tres segundos. Una web lenta o anticuada los envía directos a la competencia, para siempre. Son ventas que ni siquiera sabes que perdiste."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Nuestra web corporativa te da lo contrario: un sitio rápido, atractivo y orientado a vender que te enorgullece mostrar. Hasta siete páginas, tu propio CMS para actualizarla tú mismo, diseño responsive, SEO on-page y Google Analytics, todo por 18 000 SEK."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Es nuestro paquete más popular, y no es casualidad. ¿Te muestro ejemplos y preparo una propuesta para tu nueva web?"}]}]}$j$::jsonb),
  ('Säljpitch: MVP', 'Sales pitch: MVP', 'Pitch de ventas: MVP', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "The biggest risk with a new product isn't building the wrong thing – it's spending six months and hundreds of thousands before you know anyone even wants it."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "An MVP flips that around. We build a sharp first version with the core features in 4–6 weeks, from SEK 29,000, and you own the source code. Suddenly you have something real to show customers and investors – not a pitch, but a product."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "The fastest companies win because they learn from reality first. Shall we sketch out your MVP right now?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "El mayor riesgo de un producto nuevo no es construir algo equivocado, sino invertir medio año y cientos de miles antes de saber si alguien lo quiere."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Un MVP le da la vuelta. Construimos una primera versión afilada con las funciones esenciales en 4–6 semanas, desde 29 000 SEK, y tú eres dueño del código. De repente tienes algo real que mostrar a clientes e inversores: no una idea, sino un producto."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Las empresas más rápidas ganan porque aprenden antes de la realidad. ¿Esbozamos tu MVP ahora mismo?"}]}]}$j$::jsonb),
  ('Säljpitch: Webbapp', 'Sales pitch: Web app', 'Pitch de ventas: Aplicación web', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "When an ordinary website isn't enough, you're often stuck in manual work, spreadsheets and double effort. Imagine the system doing it for you instead."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "We build a custom web app that solves exactly your problem – login, roles, database, admin panel and an architecture that grows with you, from SEK 49,000. It's the difference between chasing your process and owning it."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tell me how you work today and I'll show you concretely what we can automate away. How much time would you win each week?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Cuando una web normal no basta, sueles quedar atrapado en trabajo manual, hojas de cálculo y tareas duplicadas. Imagina que el sistema lo hace por ti."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Construimos una aplicación web a medida que resuelve justo tu problema: inicio de sesión, roles, base de datos, panel de administración y una arquitectura que crece contigo, desde 49 000 SEK. Es la diferencia entre perseguir tu proceso y dominarlo."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Cuéntame cómo trabajáis hoy y te muestro en concreto qué podemos automatizar. ¿Cuánto tiempo ganaríais cada semana?"}]}]}$j$::jsonb),
  ('Säljpitch: Mobilapp', 'Sales pitch: Mobile app', 'Pitch de ventas: Aplicación móvil', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "There's no more valuable spot than your customer's pocket. Your own app means you're one tap away – with push notifications that take you right into their day, again and again."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "We build for both iOS and Android from the same codebase – faster and cheaper than two separate apps. From SEK 79,000 you get development, push, backend and publishing in the App Store and Google Play. We handle the whole journey from idea to launch."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Picture your customers with your logo on their home screen. What should the app do for them – and for your repeat sales?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "No hay lugar más valioso que el bolsillo de tu cliente. Tu propia app significa estar a un toque de distancia, con notificaciones push que te llevan directo a su día, una y otra vez."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Desarrollamos para iOS y Android desde la misma base de código: más rápido y barato que dos apps separadas. Desde 79 000 SEK incluye desarrollo, push, backend y publicación en App Store y Google Play. Nos encargamos de todo el camino, de la idea al lanzamiento."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Imagina a tus clientes con tu logo en la pantalla de inicio. ¿Qué debe hacer la app por ellos y por tus ventas recurrentes?"}]}]}$j$::jsonb),
  ('Säljpitch: SEO Start', 'Sales pitch: SEO Start', 'Pitch de ventas: SEO Start', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Right now someone is googling exactly what you sell. The uncomfortable question: do they find you, or your competitor? Every day on page two is customers you give away for free."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "With SEO Start we lay the groundwork to turn that around. From SEK 4,900/mo you get on-page optimization, keyword analysis and a clear monthly report where you see the curve pointing up – in black and white."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "The best part? The traffic you build costs nothing per click and doesn't vanish when you stop advertising. Shall we start with a quick visibility analysis so you see where you stand today?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Ahora mismo alguien está buscando en Google justo lo que vendes. La pregunta incómoda: ¿te encuentran a ti o a tu competidor? Cada día en la segunda página son clientes que regalas gratis."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Con SEO Start ponemos la base para darle la vuelta. Desde 4 900 SEK/mes obtienes optimización on-page, análisis de palabras clave y un informe mensual claro donde ves la curva subir, negro sobre blanco."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "¿Lo mejor? El tráfico que construyes no cuesta nada por clic y no desaparece cuando dejas de anunciarte. ¿Empezamos con un análisis rápido de visibilidad para ver dónde estás hoy?"}]}]}$j$::jsonb),
  ('Säljpitch: SEO Tillväxt', 'Sales pitch: SEO Growth', 'Pitch de ventas: SEO Crecimiento', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "The top spots on Google aren't free – but they're not taken by chance either. Someone works for them every month. With SEO Growth, that someone is you."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "From SEK 9,900/mo we drive content, link building and technical SEO offensively and measurably. Position by position we take your most important keywords, and more qualified customers find you – while your competitor wonders what happened."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "This is the package for those who are serious about growing. May I show you where you rank today and exactly where we can take you?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Los primeros puestos en Google no son gratis, pero tampoco se ocupan por azar. Alguien trabaja por ellos cada mes. Con SEO Crecimiento, ese alguien eres tú."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Desde 9 900 SEK/mes impulsamos contenido, link building y SEO técnico de forma ofensiva y medible. Posición a posición conquistamos tus palabras clave más importantes, y más clientes cualificados te encuentran, mientras tu competidor se pregunta qué pasó."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Este es el paquete para quien va en serio con crecer. ¿Te muestro dónde posicionas hoy y exactamente hasta dónde podemos llevarte?"}]}]}$j$::jsonb),
  ('Säljpitch: GEO / AI-synlighet', 'Sales pitch: GEO / AI visibility', 'Pitch de ventas: GEO / Visibilidad en IA', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Your customers have already started asking ChatGPT and Perplexity instead of googling. And here's the uncomfortable part: if the AI doesn't mention you, you simply don't exist in that conversation. No second chance, no ad space."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "GEO is about becoming the one the AI recommends. From SEK 6,900/mo we do a GEO analysis, a concrete action plan and track your AI visibility continuously – on a channel your competitors haven't even thought about yet."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "This is the head start that's only available right now. Want to see how AI describes your company today – before someone else takes the spot?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tus clientes ya han empezado a preguntar a ChatGPT y Perplexity en lugar de buscar en Google. Y aquí está lo incómodo: si la IA no te menciona, simplemente no existes en esa conversación. Sin segunda oportunidad, sin espacio publicitario."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "GEO consiste en convertirte en el que la IA recomienda. Desde 6 900 SEK/mes hacemos un análisis GEO, un plan de acción concreto y seguimos tu visibilidad en IA de forma continua, en un canal en el que tus competidores ni han pensado."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Es la ventaja que solo está disponible ahora mismo. ¿Quieres ver cómo describe la IA tu empresa hoy, antes de que otro tome ese lugar?"}]}]}$j$::jsonb),
  ('Säljpitch: Designpartner', 'Sales pitch: Design partner', 'Pitch de ventas: Socio de diseño', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Good design makes you look like the market leader – and lets you charge the market leader's prices. But a full-time designer is expensive, and freelancers disappear mid-project."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "As a design partner you get a whole design department on subscription. From SEK 9,000/mo: UI/UX and graphic material, priority access and a queue where you submit requests at your own pace. Predictable cost, zero recruitment, always someone ready."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Imagine never being stuck again because you lack a designer. What are your design needs over the coming months?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Un buen diseño te hace parecer el líder del mercado y te permite cobrar como el líder del mercado. Pero un diseñador a tiempo completo es caro, y los freelance desaparecen a mitad de proyecto."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Como socio de diseño obtienes todo un departamento de diseño por suscripción. Desde 9 000 SEK/mes: UI/UX y material gráfico, acceso prioritario y una cola donde envías solicitudes a tu ritmo. Coste predecible, cero contratación, siempre alguien disponible."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Imagina no volver a bloquearte por falta de un diseñador. ¿Qué necesidades de diseño tienes los próximos meses?"}]}]}$j$::jsonb),
  ('Säljpitch: Logotyp & varumärke', 'Sales pitch: Logo & brand', 'Pitch de ventas: Logotipo y marca', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A strong brand does two things at once: customers remember you, and they're willing to pay more. A weak brand does the opposite – you become one of the crowd, forced to compete on price."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "We create a logo and identity that feels right and lasts for years. From SEK 12,000 you get a logo, colors, typography and a brand guide so everything you do looks consistent and professional – on the site, on social media, on the invoice."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "First impressions only happen once. How do you want your customers to perceive you?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Una marca fuerte hace dos cosas a la vez: los clientes te recuerdan y están dispuestos a pagar más. Una marca débil hace lo contrario: te vuelves uno más, obligado a competir por precio."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Creamos un logotipo y una identidad que encajan y duran años. Desde 12 000 SEK obtienes logotipo, colores, tipografía y una guía de marca para que todo lo que hagas se vea coherente y profesional: en la web, en redes, en la factura."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "La primera impresión solo ocurre una vez. ¿Cómo quieres que te perciban tus clientes?"}]}]}$j$::jsonb),
  ('Säljpitch: E-handel Start', 'Sales pitch: E-commerce Start', 'Pitch de ventas: E-commerce Start', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Picture your store open around the clock, taking payments while you sleep. Starting to sell online doesn't have to be expensive or complicated – and you don't have to wait."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "E-commerce Start gives you a complete store on our own platform. From SEK 19,000 setup and SEK 1,490/mo: your own CMS, payment via Klarna or Stripe, shipping, mobile-friendly design and room for up to a hundred products."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "You go live now and upgrade as sales grow. Shall we set up your store and get the first order ticking in?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Imagina tu tienda abierta las 24 horas, cobrando mientras duermes. Empezar a vender online no tiene por qué ser caro ni complicado, y no tienes que esperar."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "E-commerce Start te da una tienda completa en nuestra propia plataforma. Desde 19 000 SEK de alta y 1 490 SEK/mes: tu propio CMS, pago con Klarna o Stripe, envíos, diseño adaptado a móvil y espacio para hasta cien productos."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Te pones en marcha ya y amplías a medida que crecen las ventas. ¿Montamos tu tienda y hacemos que entre el primer pedido?"}]}]}$j$::jsonb),
  ('Säljpitch: E-handel Plus', 'Sales pitch: E-commerce Plus', 'Pitch de ventas: E-commerce Plus', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A store that starts selling but can't grow quickly becomes a bottleneck. E-commerce Plus is built for the next level – more products, more purchases, more automation."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Our most popular e-commerce package: from SEK 35,000 setup and SEK 2,490/mo you get up to a thousand products, multiple payment options, discount codes, customer accounts, newsletters and on-page SEO. All on our own platform that we manage for you."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Every feature is there to raise your average order and bring customers back. Want to see how it would work for your range?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Una tienda que empieza a vender pero no puede crecer se convierte rápido en un cuello de botella. E-commerce Plus está hecho para el siguiente nivel: más productos, más compras, más automatización."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Nuestro paquete de e-commerce más popular: desde 35 000 SEK de alta y 2 490 SEK/mes obtienes hasta mil productos, varias opciones de pago, códigos de descuento, cuentas de cliente, newsletters y SEO on-page. Todo en nuestra propia plataforma que gestionamos por ti."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Cada función está para subir tu ticket medio y hacer que los clientes vuelvan. ¿Quieres ver cómo funcionaría para tu catálogo?"}]}]}$j$::jsonb),
  ('Säljpitch: E-handel Pro', 'Sales pitch: E-commerce Pro', 'Pitch de ventas: E-commerce Pro', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "When you sell for real, the bottleneck is rarely the store – it's all the manual work around it. Orders typed by hand, stock that doesn't add up, systems that don't talk to each other."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "E-commerce Pro is our enterprise level. From SEK 59,000 setup and SEK 4,900/mo: unlimited products, ERP integration with Fortnox or Visma, B2B pricing, real-time stock, multiple languages and currencies, and priority support."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "We build an e-commerce that scales with you instead of slowing you down. Which systems does it need to connect to?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Cuando vendes en serio, el cuello de botella rara vez es la tienda: es todo el trabajo manual alrededor. Pedidos escritos a mano, stock que no cuadra, sistemas que no se hablan."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "E-commerce Pro es nuestro nivel enterprise. Desde 59 000 SEK de alta y 4 900 SEK/mes: productos ilimitados, integración ERP con Fortnox o Visma, precios B2B, stock en tiempo real, varios idiomas y monedas, y soporte prioritario."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Construimos un e-commerce que escala contigo en vez de frenarte. ¿A qué sistemas necesita conectarse?"}]}]}$j$::jsonb),
  ('Säljpitch: Startpaket (Hemsida + SEO)', 'Sales pitch: Starter bundle (Website + SEO)', 'Pitch de ventas: Paquete inicial (Web + SEO)', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A beautiful site with no visitors is a silent shop. Traffic without a selling site is buckets with holes. You need both – from day one."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "The Starter bundle combines a business website with ongoing SEO at a discounted price: SEK 18,000 plus SEK 3,900/mo. You get the whole foundation in place – a site that converts and an engine that pulls in traffic every month."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "It's the obvious first step for anyone serious about growing digitally. Shall I run the numbers for you?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Una web bonita sin visitas es una tienda en silencio. Tráfico sin una web que venda son cubos con agujeros. Necesitas ambos, desde el primer día."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "El Paquete inicial combina una web corporativa con SEO continuo a precio rebajado: 18 000 SEK más 3 900 SEK/mes. Tienes toda la base lista: una web que convierte y un motor que atrae tráfico cada mes."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Es el primer paso evidente para quien va en serio con crecer en digital. ¿Te hago los números?"}]}]}$j$::jsonb),
  ('Säljpitch: Tillväxtpaket', 'Sales pitch: Growth bundle', 'Pitch de ventas: Paquete de crecimiento', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Want to not just be seen but take market share? Then doing one thing well isn't enough – it's the whole that wins. The Growth bundle gives you the entire engine."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "From SEK 25,000 plus SEK 14,900/mo we combine a selling website, offensive SEO and GEO in one – so you dominate both Google and AI search while competitors tackle one channel at a time."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "This is the package for those who want to move positions fast and measurably. Want to see a concrete plan for the next three months?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "¿Quieres no solo aparecer, sino ganar cuota de mercado? Entonces hacer una sola cosa bien no basta: gana el conjunto. El Paquete de crecimiento te da el motor completo."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Desde 25 000 SEK más 14 900 SEK/mes combinamos una web que vende, SEO ofensivo y GEO en uno: dominas Google y la búsqueda con IA mientras la competencia ataca un canal cada vez."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Es el paquete para quien quiere avanzar posiciones rápido y de forma medible. ¿Quieres ver un plan concreto para los próximos tres meses?"}]}]}$j$::jsonb),
  ('Säljpitch: MVP-paket (MVP + Designpartner)', 'Sales pitch: MVP bundle (MVP + Design partner)', 'Pitch de ventas: Paquete MVP (MVP + Socio de diseño)', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A product that works but looks cheap loses both customers and investors. A beautiful product that doesn't work does the same. The winner has both – from the start."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "The MVP bundle combines an MVP with an ongoing design partner. From SEK 29,000 plus SEK 7,000/mo you get a working product and continuous design that refines it further – at a discounted design rate."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "It's the setup for startups that want to move fast without compromising on the impression. Tell me about your idea and I'll show you how we get going this month."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Un producto que funciona pero parece barato pierde clientes e inversores. Un producto bonito que no funciona, igual. El ganador tiene ambos, desde el principio."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "El Paquete MVP combina un MVP con un socio de diseño continuo. Desde 29 000 SEK más 7 000 SEK/mes obtienes un producto funcional y diseño continuo que lo refina, a un precio de diseño rebajado."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Es la fórmula para startups que quieren moverse rápido sin sacrificar la imagen. Cuéntame tu idea y te muestro cómo arrancamos este mes."}]}]}$j$::jsonb),
  ('Säljpitch: Full digital närvaro', 'Sales pitch: Full digital presence', 'Pitch de ventas: Presencia digital completa', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Digital is no longer something you do on the side – it's where the business is won. But juggling ten different suppliers for site, SEO, GEO and design steals time you'd rather spend on your customers."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Full digital presence gathers everything under one roof: website or app, SEO, GEO and design, with a dedicated contact who knows your business. We put together a tailored quote based on your goals."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "You focus on what you do best – we own the digital and make it deliver. Shall we book a meeting and map out your full potential?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Lo digital ya no es algo que haces aparte: es donde se gana el negocio. Pero hacer malabares con diez proveedores distintos para web, SEO, GEO y diseño roba tiempo que preferirías dedicar a tus clientes."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Presencia digital completa lo reúne todo bajo un mismo techo: web o app, SEO, GEO y diseño, con un contacto dedicado que conoce tu negocio. Preparamos un presupuesto a medida según tus objetivos."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tú te centras en lo que mejor haces; nosotros nos hacemos cargo de lo digital y hacemos que rinda. ¿Reservamos una reunión y trazamos todo tu potencial?"}]}]}$j$::jsonb),
  ('Manus: Kallt samtal', 'Script: Cold call', 'Guion: Llamada en frío', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Opening: Hi [name], this is [your name] from Applabbet. I'll keep it short and I know I'm interrupting something – give me 30 seconds to explain why I'm calling, then you tell me if it's interesting?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Hook: We help companies like yours win more customers through their website, SEO and AI visibility. I noticed [concrete observation about their site or industry] and thought there might be something to gain here."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Qualify: How do you work on bringing in new customers digitally today?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Goal – book the meeting: This is best taken on a short video call where I show you concretely what we see. Does Tuesday at 10 or Thursday at 2 work?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Remember: the goal of the call isn't to sell – it's to book the meeting. Be short, curious, and listen more than you talk."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Apertura: Hola [nombre], soy [tu nombre] de Applabbet. Seré breve y sé que interrumpo algo: dame 30 segundos para explicarte por qué llamo y luego me dices si te interesa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Gancho: Ayudamos a empresas como la tuya a conseguir más clientes mediante su web, SEO y visibilidad en IA. Vi que [observación concreta sobre su web o sector] y pensé que quizá haya algo que ganar aquí."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Calificar: ¿Cómo trabajáis hoy para conseguir nuevos clientes en digital?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Objetivo – agendar la reunión: Esto se ve mejor en una videollamada corta donde te muestro en concreto lo que vemos. ¿Te va el martes a las 10 o el jueves a las 14?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Recuerda: el objetivo de la llamada no es vender, es agendar la reunión. Sé breve, curioso y escucha más de lo que hablas."}]}]}$j$::jsonb),
  ('Manus: Första mötet', 'Script: First meeting', 'Guion: Primera reunión', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "1. Build rapport: Thank them for their time, make brief small talk and set the agenda. I thought we'd start with me getting to know your business, then I'll show how we can help, and we'll see if it's a good fit. Sound good?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "2. Needs analysis – spend most time here: Ask open questions and listen. What are your goals for the coming year? How do you get customers today? What works and what chafes? What would happen if you got twice as many enquiries?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "3. Pitch – tie it to their answers: Present only what solves what they told you. You said this was your biggest challenge – that's exactly what this package solves."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "4. Handle objections: Acknowledge, turn to value and ask a question. See objection handling."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "5. Close: Propose the next step concretely. I'll prepare a proposal and a quote by Friday, and we'll go through it together. Does that work? Book the time before you finish."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "1. Crear sintonía: Agradéceles su tiempo, haz una breve charla informal y fija la agenda. He pensado empezar conociendo vuestro negocio, luego os muestro cómo podemos ayudar y vemos si encaja. ¿Os parece bien?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "2. Análisis de necesidades – dedica aquí la mayor parte del tiempo: Haz preguntas abiertas y escucha. ¿Cuáles son vuestros objetivos para el próximo año? ¿Cómo conseguís clientes hoy? ¿Qué funciona y qué molesta? ¿Qué pasaría si recibierais el doble de solicitudes?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "3. Pitch – conéctalo con sus respuestas: Presenta solo lo que resuelve lo que te contaron. Dijiste que este era vuestro mayor reto: es justo lo que resuelve este paquete."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "4. Maneja objeciones: Reconoce, convierte en valor y haz una pregunta. Consulta el manejo de objeciones."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "5. Cierre: Propón el siguiente paso en concreto. Preparo una propuesta y un presupuesto para el viernes y lo revisamos juntos. ¿Te va bien? Agenda la hora antes de terminar."}]}]}$j$::jsonb),
  ('Invändning: Det är för dyrt', 'Objection: It''s too expensive', 'Objeción: Es demasiado caro', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "When someone says it's too expensive, they usually mean they don't see the value yet – not that the money is missing. Acknowledge, then turn the conversation to return."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Reply: I understand, it's an investment. May I ask – what is a new customer worth to you? If the site brings in just one extra customer a month, it's paid for itself. We can also start at a smaller level and build on when it delivers results."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Question: What would need to happen for this to feel like an obvious investment?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Cuando alguien dice que es demasiado caro, suele significar que aún no ve el valor, no que falte el dinero. Reconócelo y lleva la conversación al retorno."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Respuesta: Lo entiendo, es una inversión. ¿Puedo preguntar cuánto vale un cliente nuevo para ti? Si la web trae solo un cliente extra al mes, ya se ha pagado sola. También podemos empezar con un nivel más pequeño y ampliar cuando dé resultados."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pregunta: ¿Qué tendría que pasar para que esto te pareciera una inversión evidente?"}]}]}$j$::jsonb),
  ('Invändning: Vi har redan en hemsida', 'Objection: We already have a website', 'Objeción: Ya tenemos una web', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "That they have a website is good – it means they understand the value. The question is whether it performs."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Reply: Great, then you already have the foundation. May I ask – how many customers or leads does it bring in a month? Many websites are pretty brochures that don't sell. We can do a quick analysis and show you exactly where you're losing visitors."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Question: Shall I run a free analysis of your current site so you can see how it holds up?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Que tengan una web es bueno: significa que entienden el valor. La cuestión es si rinde."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Respuesta: Estupendo, entonces ya tenéis la base. ¿Puedo preguntar cuántos clientes o leads trae al mes? Muchas webs son folletos bonitos que no venden. Podemos hacer un análisis rápido y mostraros exactamente dónde perdéis visitantes."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pregunta: ¿Hago un análisis gratuito de vuestra web actual para que veáis cómo está?"}]}]}$j$::jsonb),
  ('Invändning: Vi gör det själva internt', 'Objection: We do it ourselves in-house', 'Objeción: Lo hacemos nosotros internamente', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Respect the competence, but point to time and opportunity cost."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Reply: It's impressive that you have the skills in-house. The question is whether that's where you make the most money – every hour on the website or SEO is an hour away from your core business. We do it faster so you can focus on what you do best."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Question: What would you rather spend those hours on?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Respeta la competencia, pero señala el tiempo y el coste de oportunidad."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Respuesta: Es admirable que tengáis la capacidad internamente. La cuestión es si ahí es donde más dinero ganáis: cada hora en la web o el SEO es una hora fuera de vuestro negocio principal. Nosotros lo hacemos más rápido para que os centréis en lo que mejor hacéis."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pregunta: ¿En qué preferiríais invertir esas horas?"}]}]}$j$::jsonb),
  ('Invändning: Vi har ingen tid just nu', 'Objection: We have no time right now', 'Objeción: Ahora mismo no tenemos tiempo', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Lack of time is often a question of priorities. Make it easy and low-threshold."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Reply: That's exactly why we're a good partner – we handle pretty much everything for you, you just need a short check-in. And the best time to build visibility is before you need it. Shall we book 20 minutes next week, with no obligation?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Question: Which day suits best – Tuesday or Thursday?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "La falta de tiempo suele ser una cuestión de prioridades. Hazlo fácil y de bajo compromiso."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Respuesta: Justo por eso somos un buen socio: nos encargamos de prácticamente todo por vosotros, solo necesitáis una breve puesta al día. Y el mejor momento para construir visibilidad es antes de necesitarla. ¿Reservamos 20 minutos la próxima semana, sin compromiso?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pregunta: ¿Qué día os viene mejor, el martes o el jueves?"}]}]}$j$::jsonb),
  ('Invändning: Skicka information så återkommer vi', 'Objection: Send some information and we''ll get back to you', 'Objeción: Envíanos información y os contactamos', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "The classic polite brush-off. Keep the initiative without being pushy."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Reply: Absolutely, I'll gladly send something. To make it relevant – what matters most to you right now: more customers, a more modern site or better visibility? Then I'll send examples that fit you, and we'll have a quick check-in later this week."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Question: Does a short follow-up on Friday work?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "El clásico rechazo cortés. Mantén la iniciativa sin ser insistente."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Respuesta: Por supuesto, te envío algo con gusto. Para que sea relevante, ¿qué es lo más importante para ti ahora: más clientes, una web más moderna o mejor visibilidad? Así te mando ejemplos que encajen y hacemos una breve puesta al día más adelante esta semana."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pregunta: ¿Te va bien un seguimiento corto el viernes?"}]}]}$j$::jsonb),
  ('Invändning: Vi är nöjda med vår nuvarande leverantör', 'Objection: We''re happy with our current supplier', 'Objeción: Estamos contentos con nuestro proveedor actual', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Never attack the competitor. Plant a seed and keep the door open."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Reply: Great that you have someone you're happy with – that's valuable. We don't need to replace them. Many customers use us as a complement for things like SEO or GEO, which are often missing. May I show what you could add?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Question: What does your current supplier do really well – and what are you missing?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Nunca ataques al competidor. Siembra una semilla y deja la puerta abierta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Respuesta: Qué bien que tengáis a alguien con quien estáis a gusto, eso vale mucho. No hace falta reemplazarlos. Muchos clientes nos usan como complemento para cosas como SEO o GEO, que suelen faltar. ¿Os muestro qué podríais añadir?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pregunta: ¿Qué hace muy bien vuestro proveedor actual y qué echáis en falta?"}]}]}$j$::jsonb),
  ('Invändning: Funkar SEO och GEO verkligen?', 'Objection: Do SEO and GEO really work?', 'Objeción: ¿De verdad funcionan el SEO y el GEO?', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Meet skepticism with concrete examples and measurability."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Reply: You're right to be critical – there are a lot of empty promises in this industry. The difference is that we measure everything – you see ranking, traffic and leads in black and white every month. And GEO is new: your competitors aren't showing up in ChatGPT yet, which is your head start."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Question: Shall I show how you rank today and what's possible in three months?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Responde al escepticismo con ejemplos concretos y mensurabilidad."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Respuesta: Haces bien en ser crítico: hay muchas promesas vacías en este sector. La diferencia es que nosotros lo medimos todo: ves ranking, tráfico y leads negro sobre blanco cada mes. Y el GEO es nuevo: tus competidores aún no aparecen en ChatGPT, y esa es tu ventaja."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pregunta: ¿Te muestro cómo posicionas hoy y qué es posible en tres meses?"}]}]}$j$::jsonb),
  ('Invändning: Vi måste tänka på det', 'Objection: We need to think about it', 'Objeción: Tenemos que pensarlo', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "A soft no often hides an uncertainty. Find out what's blocking it."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Reply: Of course, smart not to rush. May I ask – is it the price, the timing or something else you want to think over? Then I can help you with that specific part instead of you sitting and pondering on your own."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Question: What's the biggest question that needs answering for you to feel confident?"}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Un no suave suele esconder una duda. Averigua qué lo frena."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Respuesta: Por supuesto, es sensato no precipitarse. ¿Puedo preguntar si es el precio, el momento u otra cosa lo que queréis meditar? Así os ayudo justo con esa parte en lugar de que le deis vueltas solos."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pregunta: ¿Cuál es la mayor duda que hay que resolver para que os sintáis seguros?"}]}]}$j$::jsonb)
) AS v(title_sv, title_en, title_es, body_en, body_es)
JOIN public.training_categories cat ON cat.slug = 'saljmanus'
WHERE ti.category_id = cat.id AND ti.title = v.title_sv;
